import sys

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    H = int(data[0])
    W = int(data[1])
    K = int(data[2])
    grid = data[3:3+H]

    min_ops = float('inf')

    for i in range(H):
        row = grid[i]
        for j in range(W - K + 1):
            ops = 0
            for k in range(K):
                if row[j + k] == 'x':
                    ops = float('inf')
                    break
                elif row[j + k] == '.':
                    ops += 1
            if ops < min_ops:
                min_ops = ops

    for j in range(W):
        for i in range(H - K + 1):
            ops = 0
            for k in range(K):
                if grid[i + k][j] == 'x':
                    ops = float('inf')
                    break
                elif grid[i + k][j] == '.':
                    ops += 1
            if ops < min_ops:
                min_ops = ops

    if min_ops == float('inf'):
        print(-1)
    else:
        print(min_ops)

if __name__ == "__main__":
    main()
